            package main

import (
	"log"
	"net/http"
	"net/url"
	"time"

	"github.com/gofiber/fiber/v2"
)

// Simulate a storage/database for the configuration
var savedWebhookURL string

// WebhookRequest represents the expected JSON payload
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook receives a POST request, validates the webhook URL via a GET request,
// saves the configuration, and returns a JSON response.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	req := new(WebhookRequest)

	// Parse the JSON body
	if err := ctx.BodyParser(req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid request body. Expected JSON with 'webhook_url'.",
		})
	}

	// Validate the URL format
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil || (parsedURL.Scheme != "http" && parsedURL.Scheme != "https") {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL provided.",
		})
	}

	// Create an HTTP client with a strict 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a test GET request to validate the webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to reach the webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Save the configuration (in-memory for this example)
	savedWebhookURL = req.WebhookURL

	// Return a successful JSON response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"message":     "Webhook configured and validated successfully.",
		"webhook_url": savedWebhookURL,
	})
}

func main() {
	// Initialize a new Fiber app
	app := fiber.New()

	// Register the ConfigureWebhook handler
	app.Post("/api/webhook", ConfigureWebhook)

	// Start the server on port 3000
	log.Println("Server starting on :3000")
	if err := app.Listen(":3000"); err != nil {
		log.Fatalf("Error starting server: %v", err)
	}
}

