            package main

import (
	"log"
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// ConfigStore acts as a simple in-memory storage for the webhook configuration.
// In a real-world scenario, this would likely be a database.
var ConfigStore struct {
	sync.RWMutex
	WebhookURL string
}

// WebhookRequest represents the expected JSON payload.
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook receives a POST request, validates the webhook URL via a GET request,
// saves the configuration, and returns a JSON response.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var payload WebhookRequest

	// Parse the JSON body
	if err := ctx.BodyParser(&payload); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON payload",
		})
	}

	// Basic validation to ensure the URL is provided
	if payload.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url field is required",
		})
	}

	// Create an HTTP client with a strict 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a test GET request to validate the webhook URL
	resp, err := client.Get(payload.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Save the configuration safely using a mutex
	ConfigStore.Lock()
	ConfigStore.WebhookURL = payload.WebhookURL
	ConfigStore.Unlock()

	// Return a successful JSON response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"message":     "Webhook configured and validated successfully",
		"webhook_url": payload.WebhookURL,
		"status_code": resp.StatusCode,
