import (
	"context"
	"log"
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the expected JSON payload for the request.
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// Response represents the JSON response structure.
type Response struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

var (
	// Global variables to store the configuration.
	// A mutex is used to ensure safe concurrent access.
	configMutex     sync.Mutex
	savedWebhookURL string
)

// ConfigureWebhook handles the webhook configuration request.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig

	// Parse JSON body
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Invalid JSON body",
		})
	}

	// Validate that webhook_url is provided
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Create a context with a 3-second timeout for the test request
	reqCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Prepare the GET request
	httpReq, err := http.NewRequestWithContext(reqCtx, http.MethodGet, config.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Invalid webhook URL format",
		})
	}

	// Initialize HTTP client with a 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send the test GET request
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.Status(fiber.StatusBadGateway).JSON(Response{
			Success: false,
			Message: "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the response status is successful (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadGateway).JSON(Response{
			Success: false,
			Message: "Webhook URL returned non-success status code",
		})
	}

	// Save the configuration safely
	configMutex.Lock()
	savedWebhookURL = config.WebhookURL
	configMutex.Unlock()

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(Response{
		Success: true,
		Message: "Webhook configured and validated successfully",
	})
}

func main() {
	// Initialize a new Fiber app
	app := fiber.New()

	// Register the handler for POST requests
	app.Post("/webhook", ConfigureWebhook)

	// Start the server on port 3000
	log.Println("Server is starting on :3000...")
	if err := app.Listen(":3000"); err != nil {
		log.Fatalf("Error starting server: %v", err)
	}
}

