import (
	"log"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// Global variable to simulate saving the configuration in memory.
// In a real-world application, this would likely be saved to a database.
var savedWebhookURL string

// WebhookRequest represents the expected JSON payload.
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook receives a POST request with a JSON body containing a webhook_url,
// validates it by sending a GET request with a 3-second timeout, and saves it.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookRequest

	// Parse the JSON body
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON body",
		})
	}

	// Check if the webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url field is required",
		})
	}

	// Create an HTTP client with a 3-second timeout as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a test GET request to validate the webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Save the configuration
	savedWebhookURL = req.WebhookURL

	// Return a JSON response with the result
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"message":     "Webhook successfully validated and configured",
		"webhook_url": savedWebhookURL,
		"test_status": resp.StatusCode,
	})
}

func main() {
	// Initialize a new Fiber app
	app := fiber.New()

	// Register the ConfigureWebhook handler for POST requests
	app.Post("/webhook/configure", ConfigureWebhook)

	// Start the server
	log.Println("Server is running on port 3000")
	if err := app.Listen(":3000"); err != nil {
		log.Fatalf("Failed to start server: %v", err)
	}
}

