package main

import (
	"log"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookRequest represents the expected JSON body for the request.
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// Global variable to act as a mock database/storage for the webhook configuration.
var savedWebhookURL string

// ConfigureWebhook receives a POST request, validates the webhook_url via a GET request
// with a 3-second timeout, saves the configuration, and returns a JSON response.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookRequest

	// Parse the JSON body
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON body",
		})
	}

	// Ensure the webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url field is required",
		})
	}

	// Create an HTTP client with a 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a test GET request to validate the webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Ensure the webhook responds with a valid HTTP status code (e.g., 2xx or 3xx)
	if resp.StatusCode >= 400 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook URL returned an error status code",
		})
	}

	// Save the configuration (mocked by saving to a global variable)
	savedWebhookURL = req.WebhookURL

	// Return a successful JSON response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"message":     "Webhook configured and validated successfully",
		"webhook_url": savedWebhookURL,
	})
}

func main() {
	// Initialize a new Fiber app
	app := fiber.New()

	// Register the ConfigureWebhook handler
	app.Post("/webhook/configure", ConfigureWebhook)

	// Start the server on port 3000
	log.Println("Server is starting on port 3000...")
	if err := app.Listen(":3000"); err != nil {
		log.Fatalf("Failed to start server: %v", err)
	}
}

