package main

import (
	"log"
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookPayload represents the expected JSON body for the request.
type WebhookPayload struct {
	WebhookURL string `json:"webhook_url"`
}

var (
	// Mock database/storage for the webhook configuration
	savedWebhookURL string
	webhookMutex    sync.RWMutex
)

// ConfigureWebhook receives a POST request, validates the webhook_url via a GET request,
// saves the configuration, and returns a JSON response.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var payload WebhookPayload

	// Parse the JSON body
	if err := ctx.BodyParser(&payload); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON payload",
		})
	}

	// Ensure the webhook_url is not empty
	if payload.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url field is required",
		})
	}

	// Create an HTTP client with a 3-second timeout as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Validate the webhook URL by sending a GET request
	resp, err := client.Get(payload.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to validate webhook URL",
			"details": err.Error(),
		})
	}
	defer resp.Body.Close()

	// Save the configuration safely
	webhookMutex.Lock()
	savedWebhookURL = payload.WebhookURL
	webhookMutex.Unlock()

	// Return a successful JSON response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured and validated successfully",
		"data": fiber.Map{
			"webhook_url": payload.WebhookURL,
		},
	})
}

func main() {
	// Initialize a new Fiber app
	app := fiber.New()

	// Define the route
	app.Post("/webhook", ConfigureWebhook)

	// Start the server
	log.Println("Server starting on :3000")
	if err := app.Listen(":3000"); err != nil {
		log.Fatalf("Failed to start server: %v", err)
	}
}

