            package main

import (
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookRequest represents the expected JSON payload
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// Mock storage for the webhook configuration
var (
	savedWebhookURL string
	storageMutex    sync.RWMutex
)

// ConfigureWebhook receives a POST request, validates the webhook_url via a GET request
// with a 3-second timeout, saves it, and returns a JSON response.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookRequest

	// Parse the JSON body
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON body",
		})
	}

	// Ensure webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Create an HTTP client with a 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a test GET request to validate the webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadGateway).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to reach webhook URL",
			"details": err.Error(),
		})
	}
	defer resp.Body.Close()

	// Ensure the webhook URL returns a successful status code
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadGateway).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook URL returned a non-successful HTTP status",
			"status":  resp.StatusCode,
		})
	}

	// Save the configuration safely
	storageMutex.Lock()
	savedWebhookURL = req.WebhookURL
	storageMutex.Unlock()

	// Return a successful JSON response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"message":     "Webhook successfully validated and configured",
		"webhook_url": req.WebhookURL,
	})
}

func main() {
	// Initialize a new Fiber app
	app := fiber.New()

	// Register the ConfigureWebhook handler
	app.Post("/webhook/configure", ConfigureWebhook)

	// Start the server on port 3000
	err := app.Listen(":3000")
	if err != nil {
		panic(err)
	}
}

