import (
	"log"
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the expected JSON payload
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

var (
	// Global variables to simulate saving the configuration
	savedWebhookURL string
	configMutex     sync.RWMutex
)

// ConfigureWebhook receives a POST request, validates the webhook_url via a GET request,
// and saves the configuration if reachable.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	payload := new(WebhookConfig)

	// Parse JSON body
	if err := ctx.BodyParser(payload); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON payload",
		})
	}

	// Check if webhook_url is provided
	if payload.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate the webhook URL by sending a GET request
	// Requirement: set the timeout to 3 seconds
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(payload.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Save the configuration safely
	configMutex.Lock()
	savedWebhookURL = payload.WebhookURL
	configMutex.Unlock()

	// Return successful JSON response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"message":     "Webhook configured and validated successfully",
		"webhook_url": payload.WebhookURL,
	})
}

func main() {
	// Initialize a new Fiber app
	app := fiber.New()

	// Register the handler
	app.Post("/api/webhook/configure", ConfigureWebhook)

	// Start the server
	log.Println("Server is running on port 3000...")
	if err := app.Listen(":3000"); err != nil {
		log.Fatalf("Failed to start server: %v", err)
	}
}

