	"github.com/gofiber/fiber/v2"
)

// WebhookRequest represents the expected JSON body for the webhook configuration.
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

var (
	// In-memory storage to save the webhook configuration.
	savedWebhookURL string
	configMutex     sync.RWMutex
)

// ConfigureWebhook handles the POST request to configure and validate a webhook URL.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookRequest

	// Parse the JSON body
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON body",
		})
	}

	// Check if webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url field is required",
		})
	}

	// Validate URL format
	if _, err := url.ParseRequestURI(req.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook_url format",
		})
	}

	// Create an HTTP client with a strict 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a test GET request to validate the webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadGateway).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to reach the webhook URL",
			"details": err.Error(),
		})
	}
	defer resp.Body.Close()

	// Ensure the webhook endpoint returned a successful status code
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadGateway).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook URL returned a non-success HTTP status",
			"status":  resp.StatusCode,
		})
	}

	// Save the configuration safely
	configMutex.Lock()
	savedWebhookURL = req.WebhookURL
	configMutex.Unlock()

	// Return a successful JSON response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"message":     "Webhook configured and validated successfully",
		"webhook_url": req.WebhookURL,
	})
}

func main() {
	// Initialize a new Fiber app
	app := fiber.New()

	// Register the handler for the POST request
	app.Post("/webhook/configure", ConfigureWebhook)

	// Start the server
	log.Println("Server is running on port 3000...")
	if err := app.Listen(":3000"); err != nil {
		log.Fatalf("Failed to start server: %v", err)
	}
}

