// savedWebhookURL simulates a database or memory store for the configuration
var savedWebhookURL string

// WebhookRequest represents the expected JSON payload
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook receives a POST request with a webhook_url, validates it via GET, and saves it.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	req := new(WebhookRequest)

	// Parse the JSON body
	if err := ctx.BodyParser(req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Invalid request body. Please provide a valid JSON.",
		})
	}

	// Basic validation for empty URL
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "The 'webhook_url' field is required.",
		})
	}

	// Validate URL format
	if _, err := url.ParseRequestURI(req.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Invalid 'webhook_url' format.",
		})
	}

	// Create an HTTP client with a strict 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a test GET request to the provided webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadGateway).JSON(fiber.Map{
			"error":   "Failed to validate webhook URL. Test request failed.",
			"details": err.Error(),
		})
	}
	defer resp.Body.Close()

	// Save the configuration (in-memory for this example)
	savedWebhookURL = req.WebhookURL

	// Return a successful JSON response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"message":     "Webhook successfully validated and configured.",
		"webhook_url": savedWebhookURL,
		"test_status": resp.StatusCode,
	})
}

func main() {
	// Initialize a new Fiber app
	app := fiber.New()

	// Register the ConfigureWebhook handler on a POST route
	app.Post("/webhook/configure", ConfigureWebhook)

	// Start the server on port 3000
	log.Println("Server is starting on :3000...")
	if err := app.Listen(":3000"); err != nil {
		log.Fatalf("Failed to start server: %v", err)
	}
}

