package main

import (
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// Global variables to simulate saving the configuration
var (
	savedWebhookURL string
	configMutex     sync.RWMutex
)

// WebhookRequest represents the expected JSON payload
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook receives a POST request, validates the webhook URL via a GET request,
// saves the configuration, and returns a JSON response.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookRequest

	// Parse the JSON body
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON body",
		})
	}

	// Ensure the webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url field is required",
		})
	}

	// Create an HTTP client with a 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a test GET request to validate the webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Optionally check if the status code is successful (e.g., 2xx or 3xx)
	if resp.StatusCode >= 400 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook URL returned an error status code",
			"status":  resp.StatusCode,
		})
	}

	// Save the configuration safely
	configMutex.Lock()
	savedWebhookURL = req.WebhookURL
	configMutex.Unlock()

	// Return a successful JSON response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"message":     "Webhook configured successfully",
		"webhook_url": req.WebhookURL,
	})
}

func main() {
	// Initialize a new Fiber app
	app := fiber.New()

	// Register the ConfigureWebhook handler
	app.Post("/webhook", ConfigureWebhook)

	// Start the server on port 3000
	err := app.Listen(":3000")
	if err != nil {
		panic(err)
	}
}

