type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// Global state to simulate saving the configuration
var (
	configMutex     sync.RWMutex
	savedWebhookURL string
)

// ConfigureWebhook receives a POST request, validates the webhook_url via a GET request,
// saves the configuration, and returns a JSON response.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookRequest

	// Parse the JSON body
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON body",
		})
	}

	// Validate that the webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Create an HTTP client with a strict 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a test GET request to validate the webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to validate webhook URL",
			"details": err.Error(),
		})
	}
	defer resp.Body.Close()

	// Optionally check if the status code indicates success
	if resp.StatusCode < 200 || resp.StatusCode >= 400 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook URL returned a non-success status code",
			"status":  resp.StatusCode,
		})
	}

	// Save the configuration safely
	configMutex.Lock()
	savedWebhookURL = req.WebhookURL
	configMutex.Unlock()

	// Return success JSON response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"message":     "Webhook configured and validated successfully",
		"webhook_url": req.WebhookURL,
	})
}

func main() {
	// Initialize a new Fiber app
	app := fiber.New()

	// Register the handler for POST requests
	app.Post("/api/webhook/configure", ConfigureWebhook)

	// Start the server on port 3000
	err := app.Listen(":3000")
	if err != nil {
		panic(err)
	}
}

